const req = label && label.v;
if (!req || typeof req !== 'object') return;
const ensureIdx = (n) => Number.isInteger(n) ? n : 0;
if (req.op === 'write' && Array.isArray(req.records)) {
  let applied = 0;
  for (const rec of req.records) {
    if (!rec || typeof rec !== 'object') continue;
    if (typeof rec.k !== 'string' || !rec.k) continue;
    if (typeof rec.t !== 'string' || !rec.t) continue;
    V1N.table.addLabel(ensureIdx(rec.p), ensureIdx(rec.r), ensureIdx(rec.c), rec.k, rec.t, rec.v);
    applied += 1;
  }
  return { status: 'ok', applied };
}
if (req.op === 'remove' && Array.isArray(req.records)) {
  let removed = 0;
  for (const rec of req.records) {
    if (!rec || typeof rec !== 'object') continue;
    if (typeof rec.k !== 'string' || !rec.k) continue;
    V1N.table.removeLabel(ensureIdx(rec.p), ensureIdx(rec.r), ensureIdx(rec.c), rec.k);
    removed += 1;
  }
  return { status: 'ok', removed };
}
return { status: 'error', reason: 'unsupported_op' };

const req = label && label.v;
if (!req || typeof req !== 'object') return { status: 'error', reason: 'invalid_request' };
