const targetPin = typeof req.target_pin === 'string' ? req.target_pin.trim() : '';
if (!targetCell || !targetPin) return { status: 'error', reason: 'missing_target' };
const ensureIdx = (n) => Number.isInteger(n) ? n : 0;
V1N.addLabel('mt_write_req', 'pin.in', {
  op: 'write',
  records: [{
    p: ensureIdx(targetCell.p),
    r: ensureIdx(targetCell.r),
    c: ensureIdx(targetCell.c),
    k: targetPin,
    t: 'pin.in',
    v: req.value ?? null
  }]
});
return { status: 'ok', dispatched: true };

const req = label && label.v;
