  version: 'v1',
  type: 'pin_payload',
  op_id: opId,
  source_model_id: sourceModelId,
  pin,
  payload: req.payload ?? null,
  timestamp: Date.now()
});
return { status: 'ok', bus_out_key: busOutKey };
